 1→package com.exam.config;
 2→
 3→import com.fasterxml.jackson.databind.ObjectMapper;
 4→import lombok.RequiredArgsConstructor;
 5→import org.springframework.context.annotation.Bean;
 6→import org.springframework.context.annotation.Configuration;
 7→import org.springframework.http.HttpStatus;
 8→import org.springframework.http.MediaType;
 9→import org.springframework.security.config.annotation.web.builders.HttpSecurity;
10→import org.springframework.security.config.annotation.web.configuration.EnableWebSecurity;
11→import org.springframework.security.config.Customizer;
12→import org.springframework.security.config.annotation.web.configurers.AbstractHttpConfigurer;
13→import org.springframework.security.config.http.SessionCreationPolicy;
14→import org.springframework.security.web.SecurityFilterChain;
15→import org.springframework.security.web.authentication.UsernamePasswordAuthenticationFilter;
16→
17→import java.util.Map;
18→
19→/**
20→ * Spring Security 配置
21→ */
22→@Configuration
23→@EnableWebSecurity
24→@RequiredArgsConstructor
25→public class SecurityConfig {
26→
27→    private final JwtAuthenticationFilter jwtAuthenticationFilter;
28→    private final ObjectMapper objectMapper;
29→
30→    @Bean
31→    public SecurityFilterChain securityFilterChain(HttpSecurity http) throws Exception {
32→        http
33→            .cors(Customizer.withDefaults())
34→            .csrf(AbstractHttpConfigurer::disable)
35→            .sessionManagement(session -> session.sessionCreationPolicy(SessionCreationPolicy.STATELESS))
36→            .authorizeHttpRequests(auth -> auth
37→                .requestMatchers("/api/auth/oauth2/**").permitAll()
38→                .requestMatchers("/api/open/**").authenticated()
39→                .requestMatchers("/api/admin/**").hasRole("ADMIN")
40→                .requestMatchers("/api/**").authenticated()
41→                .anyRequest().permitAll()
42→            )
43→            .addFilterBefore(jwtAuthenticationFilter, UsernamePasswordAuthenticationFilter.class)
44→            .exceptionHandling(ex -> ex
45→                .authenticationEntryPoint((request, response, authException) -> {
46→                    response.setStatus(HttpStatus.UNAUTHORIZED.value());
47→                    response.setContentType(MediaType.APPLICATION_JSON_VALUE);
48→                    response.setCharacterEncoding("UTF-8");
49→                    String body = objectMapper.writeValueAsString(
50→                            Map.of("code", 401, "message", "未登录或登录已过期", "data", ""));
51→                    response.getWriter().write(body);
52→                })
53→                .accessDeniedHandler((request, response, accessDeniedException) -> {
54→                    response.setStatus(HttpStatus.FORBIDDEN.value());
55→                    response.setContentType(MediaType.APPLICATION_JSON_VALUE);
56→                    response.setCharacterEncoding("UTF-8");
57→                    String body = objectMapper.writeValueAsString(
58→                            Map.of("code", 403, "message", "无权限访问", "data", ""));
59→                    response.getWriter().write(body);
60→                })
61→            );
62→
63→        return http.build();
64→    }
65→}
